arguments.new_str:
using Microsoft.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers
        .SdcaLogisticRegression(labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// --- Evaluate ---
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

Console.WriteLine($"Accuracy:  {metrics.Accuracy:F4}");
Console.WriteLine($"AUC:       {metrics.AreaUnderRocCurve:F4}");
Console.WriteLine($"F1 Score:  {metrics.F1Score:F4}");

// --- Save the model and register PredictionEnginePool ---
var modelPath = Path.Combine(AppContext.BaseDirectory, "ChurnModel.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API is running.");

app.MapPost("/predict", (
    PredictionEnginePool<CustomerData, ChurnPrediction> pool,
    CustomerRequest request) =>
{
    var input = new CustomerData
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        Churned = prediction.PredictedChurned,
        prediction.Probability,
        prediction.Score
    });
});

app.Run();

public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

